import React, { useEffect, useState, useRef } from 'react';
import axios from 'axios';

const Home = () => {
    const [songs, setSongs] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(-1);
    const [isPlaying, setIsPlaying] = useState(false);
    const audioRef = useRef(null);

    const currentSong = currentIndex !== -1 ? songs[currentIndex] : null;

    useEffect(() => {
        const fetchSongs = async () => {
            try {
                const res = await axios.get('http://localhost:5000/api/songs');
                setSongs(res.data);
            } catch (err) { console.error(err); }
        };
        fetchSongs();
    }, []);

    // Xử lý khi bấm nút Play ở danh sách
    const playSong = (index) => {
        setCurrentIndex(index);
        setIsPlaying(true);
    };

    // Chuyển bài tiếp theo
    const nextSong = () => {
        const nextIndex = (currentIndex + 1) % songs.length;
        setCurrentIndex(nextIndex);
        setIsPlaying(true);
    };

    // Quay lại bài trước
    const prevSong = () => {
        const prevIndex = (currentIndex - 1 + songs.length) % songs.length;
        setCurrentIndex(prevIndex);
        setIsPlaying(true);
    };

    // Tạm dừng hoặc tiếp tục
    const togglePlay = () => {
        if (isPlaying) {
            audioRef.current.pause();
        } else {
            audioRef.current.play();
        }
        setIsPlaying(!isPlaying);
    };

    return (
        <div style={{ padding: '20px', maxWidth: '900px', margin: '0 auto', fontFamily: 'Arial', paddingBottom: '150px' }}>
            <h2 style={{ textAlign: 'center', marginBottom: '30px' }}>DANH SÁCH BÀI HÁT</h2>
            
            {/* GIỮ NGUYÊN CODE DANH SÁCH BÀI HÁT NHƯ CŨ */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
                {songs.map((song, index) => (
                    <div key={song._id} style={{
                        display: 'flex', flexDirection: 'row', alignItems: 'center', padding: '12px 20px', 
                        border: '1px solid #eee', borderRadius: '12px',
                        background: currentIndex === index ? '#f0f7ff' : '#fff',
                        boxShadow: '0 2px 5px rgba(0,0,0,0.05)', justifyContent: 'space-between'
                    }}>
                        <div style={{ display: 'flex', alignItems: 'center' }}>
                            <img src={song.imageUrl ? `http://localhost:5000${song.imageUrl}` : 'https://via.placeholder.com/60'} 
                                 style={{ width: '60px', height: '60px', marginRight: '20px', borderRadius: '8px', objectFit: 'cover' }} />
                            <div style={{ textAlign: 'left' }}>
                                <div style={{ fontWeight: 'bold', fontSize: '18px' }}>{song.title}</div>
                                <div style={{ fontSize: '14px', color: '#666' }}>{song.artist}</div>
                            </div>
                        </div>
                        <button onClick={() => playSong(index)} style={{ padding: '10px 25px', background: '#28a745', color: '#fff', border: 'none', borderRadius: '25px', cursor: 'pointer', fontWeight: 'bold' }}>
                            PLAY
                        </button>
                    </div>
                ))}
            </div>

            {/* THANH ĐIỀU KHIỂN NHẠC MỚI */}
            {currentSong && (
                <div style={{
                    position: 'fixed', bottom: 0, left: 0, right: 0, 
                    background: '#181818', color: '#fff', padding: '15px 30px', 
                    display: 'flex', alignItems: 'center', justifyContent: 'space-between', zIndex: 1000
                }}>
                    {/* Bên trái: Thông tin bài hát */}
                    <div style={{ display: 'flex', alignItems: 'center', width: '30%' }}>
                        <img src={`http://localhost:5000${currentSong.imageUrl}`} style={{ width: '50px', height: '50px', borderRadius: '4px', marginRight: '15px' }} />
                        <div style={{ textAlign: 'left' }}>
                            <div style={{ fontWeight: 'bold', fontSize: '14px' }}>{currentSong.title}</div>
                            <div style={{ fontSize: '12px', color: '#b3b3b3' }}>{currentSong.artist}</div>
                        </div>
                    </div>

                    {/* Ở giữa: Nút điều khiển */}
                    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', width: '40%' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '25px' }}>
                            <button onClick={prevSong} style={btnControlStyle}> ⏮ </button>
                            <button onClick={togglePlay} style={btnPlayStyle}>
                                {isPlaying ? '⏸' : '▶'}
                            </button>
                            <button onClick={nextSong} style={btnControlStyle}> ⏭ </button>
                        </div>
                        {/* Audio ẩn để điều khiển qua JS */}
                        <audio 
                            ref={audioRef}
                            src={`http://localhost:5000${currentSong.songUrl}`} 
                            autoPlay 
                            onEnded={nextSong}
                            onPlay={() => setIsPlaying(true)}
                            onPause={() => setIsPlaying(false)}
                        />
                    </div>

                    {/* Bên phải: Thanh âm lượng (Giữ chỗ cho cân đối) */}
                    <div style={{ width: '30%', textAlign: 'right', color: '#b3b3b3', fontSize: '12px' }}>
                        Dùng thanh cuộn để xem danh sách
                    </div>
                </div>
            )}
        </div>
    );
};

// Style cho các nút điều khiển
const btnControlStyle = {
    background: 'none', border: 'none', color: '#b3b3b3', fontSize: '24px', cursor: 'pointer', transition: '0.2s'
};

const btnPlayStyle = {
    background: '#fff', border: 'none', color: '#000', width: '40px', height: '40px', 
    borderRadius: '50%', fontSize: '18px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center'
};

export default Home;
